import{_ as e,a as i,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o as s,c as l,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Authentication dan Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Safety/authentication-and-login-devices.md","filePath":"id-ID/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"id-ID/Safety/authentication-and-login-devices.md"};function r(u,a,c,m,p,g){return s(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="authentication-dan-login-device-management" tabindex="-1">Authentication dan Login Device Management <a class="header-anchor" href="#authentication-dan-login-device-management" aria-label="Permalink to &quot;Authentication dan Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> dan <code>Login Device Management</code> melindungi ImgBed admin panel, public upload entry, dan WebDAV access.</p><p>Gunakan halaman ini untuk mengatur access credentials, meninjau devices yang sudah sign in, dan revoke sessions lama saat diperlukan.</p><h2 id="di-mana-mengonfigurasinya" tabindex="-1">Di Mana Mengonfigurasinya <a class="header-anchor" href="#di-mana-mengonfigurasinya" aria-label="Permalink to &quot;Di Mana Mengonfigurasinya&quot;">​</a></h2><p>Buka admin panel, lalu masuk ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>Halaman ini memiliki dua area utama:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+e+'" alt="Authentication management" loading="lazy"></p><h2 id="fungsi-authentication-management" tabindex="-1">Fungsi Authentication Management <a class="header-anchor" href="#fungsi-authentication-management" aria-label="Permalink to &quot;Fungsi Authentication Management&quot;">​</a></h2><p>Authentication Management menyimpan access credentials.</p><p>Ada dua jenis:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication adalah upload password.</p><p>Setelah upload password diatur, visitors biasa harus memasukkannya sebelum menggunakan upload page. Ini berguna jika Anda tidak ingin public upload page terbuka untuk semua orang.</p><p><img src="'+i+'" alt="User login page" loading="lazy"></p><h3 id="mengatur-upload-password" tabindex="-1">Mengatur Upload Password <a class="header-anchor" href="#mengatur-upload-password" aria-label="Permalink to &quot;Mengatur Upload Password&quot;">​</a></h3><p>Saat upload password dikonfigurasi:</p><ul><li>Visitors harus memasukkan password sebelum menggunakan upload page.</li><li>Upload hanya tersedia setelah password diterima.</li><li>Jika user-side device sessions diaktifkan, ImgBed mencatat user-side device tersebut.</li></ul><p>Mengubah upload password akan membuat user-side sessions lama invalid. Visitors perlu memasukkan password baru lagi.</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication memakai admin username dan password.</p><p>Ini melindungi admin panel. Untuk production use, sebaiknya selalu dikonfigurasi.</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="mengatur-admin-credentials" tabindex="-1">Mengatur Admin Credentials <a class="header-anchor" href="#mengatur-admin-credentials" aria-label="Permalink to &quot;Mengatur Admin Credentials&quot;">​</a></h3><p>Saat admin username dan password dikonfigurasi:</p><ul><li>Membuka admin panel akan meminta login.</li><li>Login berhasil membuat admin device record.</li><li>Anda dapat review, clean up, atau force devices offline di Login Device Management.</li></ul><p>Mengubah admin username atau password akan membuat admin sessions lama invalid. Anda perlu sign in lagi.</p><h2 id="fungsi-login-device-management" tabindex="-1">Fungsi Login Device Management <a class="header-anchor" href="#fungsi-login-device-management" aria-label="Permalink to &quot;Fungsi Login Device Management&quot;">​</a></h2><p>Login Device Management menampilkan devices yang pernah sign in.</p><p>Ini membantu memeriksa:</p><ul><li>Devices mana yang mengakses admin panel.</li><li>Devices mana yang mengakses user-side upload page.</li><li>WebDAV clients mana yang connected.</li><li>Apakah device session masih valid.</li><li>Apakah devices lama perlu force offline.</li></ul><p>Halaman ini memiliki tiga tabs:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>Di bagian atas Login Device Management, Anda dapat mengatur global cookie behavior.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>Mengontrol berapa hari user-side login dapat tetap active.</p><p>Contohnya, jika diatur ke 14 days, visitors biasanya tidak perlu memasukkan upload password lagi dalam 14 hari.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>Mengontrol berapa hari admin login dapat tetap active.</p><p>Contohnya, jika diatur ke 14 days, administrators biasanya tidak perlu sign in lagi dalam 14 hari.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>Saat Secure mode aktif, browsers hanya mengirim login cookies lewat HTTPS.</p><p>Aktifkan untuk production HTTPS sites. Jangan aktifkan untuk local HTTP testing, atau Anda bisa melihat perilaku &quot;login berhasil, tetapi refresh membuat saya logout&quot;.</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab menampilkan devices yang sign in ke admin panel.</p><p>Device records hanya muncul setelah admin credentials dikonfigurasi dan admin panel diakses lewat login.</p><p>Setiap device card dapat menampilkan:</p><ul><li>Device dan browser information</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>Jika melihat device yang tidak dikenal, gunakan <code>Force Offline</code> untuk membuatnya invalid.</p><h2 id="clean-up-old-devices" tabindex="-1">Clean Up Old Devices <a class="header-anchor" href="#clean-up-old-devices" aria-label="Permalink to &quot;Clean Up Old Devices&quot;">​</a></h2><p><code>Clean Up Old Devices</code> menghapus login records lama di tab saat ini secara bulk.</p><p>Gunakan saat Anda mencurigai sessions lama masih active di devices lain.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> membuat satu device session invalid.</p><p>Setelah device dipaksa offline:</p><ul><li>Admin devices harus sign in lagi.</li><li>User-side devices harus memasukkan upload password lagi.</li><li>WebDAV clients harus authenticate lagi.</li></ul><p>Expired atau invalid devices juga dapat dihapus.</p><h2 id="sign-out-current-device" tabindex="-1">Sign Out Current Device <a class="header-anchor" href="#sign-out-current-device" aria-label="Permalink to &quot;Sign Out Current Device&quot;">​</a></h2><p>Current device card ditandai sebagai <code>Current Device</code>.</p><p>Setelah sign out current device:</p><ul><li>Current admin session akan sign out.</li><li>Current user-side session akan sign out.</li></ul><p>Anda perlu sign in lagi sebelum melanjutkan penggunaan area tersebut.</p>',65)])])}const v=t(d,[["render",r]]);export{b as __pageData,v as default};
